    const h = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{font-family:'맑은 고딕',sans-serif;line-height:1.8;padding:40px;white-space:pre-wrap}</style></head><body>${lines.join('\n')}</body></html>`;
